import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"67. Long Service Leave","description":"","frontmatter":{"title":"67. Long Service Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","annual-leave","long-service-leave","employment"]},"headers":[],"relativePath":"ebas/mspp/leave/67-long-service-leave.md","filePath":"ebas/mspp/leave/67-long-service-leave.md"}'),r={name:"ebas/mspp/leave/67-long-service-leave.md"};function i(s,e,l,p,c,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_67-long-service-leave" tabindex="-1">67. Long Service Leave <a class="header-anchor" href="#_67-long-service-leave" aria-label="Permalink to &quot;67. Long Service Leave&quot;">​</a></h1><p><strong>67.1</strong> Scope This clause contains several parts:</p><p><strong>a.</strong> Part 2 applies to full-time Employees, part-time Employees, Locum Pharmacists, and Regular Casual Employees only.</p><p><strong>b.</strong> Part 3 applies to Other Casual Employees only.</p><p><strong>c.</strong> Part 4 contains common provisions that apply to all Employees.</p><p><strong>67.2</strong> Definitions The following meanings apply to the terms referred to below for the purposes of this clause unless there is a contrary intention:</p><p><strong>a.</strong> Allowable period of absence means the greater of thirteen weeks (inclusive of annual leave) or 5 weeks in addition to the total period of paid annual, long</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>service or personal leave which the Employee actually receives on termination or for which the Employee is paid in lieu.</p><p><strong>b.</strong> Continuous Service means continuous Service with the same Employer plus any prior Service of six months or more with one or more Institutions, Statutory Bodies or the Australian Red Cross Blood Service of Victoria.</p><p><strong>c.</strong> Institution means any Employer, hospital or benevolent home, community health centre, Society or Association:</p><p><strong>(i)</strong> named in <a href="/eba/ebas/mspp/schedules/1-employer-parties.html">Schedule 1</a> of this Agreement; or</p><p><strong>(ii)</strong> that was registered and subsidised pursuant to the Health Services Act 1988 (Vic) or the former Hospital and Charities Act 1958 (Vic); or</p><p><strong>(iii)</strong> publicly funded Community Health Services in Victoria that are not covered by this Agreement; or</p><p><strong>(iv)</strong> the Bush Nursing Association, and successors thereto. For the avoidance of doubt, Institution includes publicly funded Community Health Services in Victoria, not covered by this Agreement.</p><p><strong>d.</strong> LSL Act means the Long Service Leave Act 2018 (Vic).</p><p><strong>e.</strong> Month means a calendar month.</p><p><strong>f.</strong> Other Casual Employee means, for the purpose of this clause, a casual Employee under <a href="/eba/ebas/mspp/employment/25-casual-employment.html">clause 25.1c</a> who is not a Regular Casual Employee but who is taken to be continuously employed in accordance with the LSL Act.</p><p><strong>g.</strong> Pay means remuneration for an employee’s normal weekly hours of work calculated at the employee’s ordinary time rate of pay inclusive of ordinary hours, casual loadings, Higher Qualification Allowances, Radiation Safety Officer Allowance and over-Agreement payments - where a component of ordinary pay - where applicable, calculated at the employee&#39;s ordinary time rate of pay provided for in <a href="/eba/ebas/mspp/classification-salaries/40-audiologists.html">clauses 40</a> to 48 , at the time the leave is taken or if they die before the completion of leave so taken, as at the time of their death; and shall include the amount of any increase to the employee&#39;s ordinary time rate of pay which occurred during the period of leave as from the date such increase operates. Where a part-time Employee’s hours fluctuate because the Employee works additional ordinary shifts (but excluding a permanent variation), the ‘normal weekly hours of work’ will be calculated by taking an average over the preceding 12 months where this is more favourable to the Employee. If a casual Employee does not have normal weekly hours of work, Pay is calculated in accordance with section 16 of the LSL Act.</p><p><strong>h.</strong> Regular Casual Employee means, for the purpose of this clause, a casual Employee who is employed for a sequence of periods on a regular and systematic basis in accordance with <a href="/eba/ebas/mspp/employment/25-casual-employment.html">clause 25.1c</a>.</p><p><strong>i.</strong> Service means employment with an Employer, Institution, Statutory Body or the Red Cross Blood Service in Victoria (however titled).</p><p><strong>j.</strong> Statutory Body means the Hospital and Charities Commission of Victoria, the Health Commission of Victoria, the Department of Health and Human Services and the Nursing and Midwifery Board of Australia, and successors thereto.</p><p><strong>k.</strong> Transfer of business occurs in the circumstances described at s.311 of the Fair Work Act 2009 (Cth).</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>and Regular Casual Employees</p><p><strong>67.3</strong> Application of Part 2 This part only applies to:</p><p><strong>a.</strong> full-time Employees;</p><p><strong>b.</strong> part-time Employees;</p><p><strong>c.</strong> Locum Pharmacists as defined under <a href="/eba/ebas/mspp/employment/25-casual-employment.html">clause 25.4</a>; and</p><p><strong>d.</strong> Regular Casual Employees.</p><p><strong>67.4</strong> Entitlement</p><p><strong>a.</strong> Subject to clause 67.6, Employees covered by the part are entitled to:</p><p><strong>(i)</strong> 26 weeks&#39; long service leave with Pay on completion of fifteen years of Continuous Service; and</p><p><strong>(ii)</strong> thereafter 8.6667 weeks&#39; long service leave with Pay on completion of each additional five years of Continuous Service.</p><p><strong>b.</strong> Subject to clause 67.6c and 67.6d, an entitlement under clause 67.4a(i) may be taken in advance on a pro rata basis if the Employee has accrued Continuous Service of at least:</p><p><strong>(i)</strong> 10 years as at the date on which this Agreement is approved by the Fair Work Commission; or</p><p><strong>(ii)</strong> from 1 July 2021, 9 years; or</p><p><strong>(iii)</strong> from 1 July 2022, 8 years; or</p><p><strong>(iv)</strong> from 1 July 2023, 7 years.</p><p><strong>67.5</strong> Calculating Continuous Service</p><p><strong>a.</strong> Periods that count towards Continuous Service Service or prior Service during the following periods will be deemed to be continuous and will count as Continuous Service:</p><p><strong>(i)</strong> an absence from work on any form of paid leave (e.g. annual leave, personal leave, long service leave and paid parental leave);</p><p><strong>(ii)</strong> any interruption or ending of employment by the Employer if made with the intention of avoiding obligations in respect of long service leave or annual leave;</p><p><strong>(iii)</strong> any absence on account of illness or injury arising out of or in the course of the employment for a period during which an Employee is receiving accident pay (see <a href="/eba/ebas/mspp/accident-pay-allowances/90-accident-pay.html">clause 90</a>);</p><p><strong>(iv)</strong> any leave of absence of the employee where the absence is authorised in advance in writing by the Employer to be counted as service;</p><p><strong>(v)</strong> any absence from employment on defence service in accordance with section 8 of the Defence Reserve Service (Protection) Act 2001 (Cth);</p><p><strong>(vi)</strong> a period of absence on community service leave under the Act;</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(vii)</strong> in the case of unpaid absences not otherwise referenced in this subclause, subject to clause 67.9: <strong>(A)</strong> any unpaid leave that is authorised in advance in writing by the Employer to count as service; or <strong>(B)</strong> up to (but not including) [the commencement date of this Agreement], any unpaid absence from work of not more than fourteen days in any year on account of illness or injury; or <strong>(C)</strong> on and from [the commencement date of this Agreement]: (1) any period of unpaid leave taken on account of illness or injury; (2) a period of Parental Leave, including Parental Leave that is extended under <a href="/eba/ebas/allied-health/leave/70-parental-leave.html">clause 70.10</a> and 70.11; and (3) the first 52 weeks of any other type of unpaid leave not specifically referenced in this subclause 67.5a(vii); and</p><p><strong>(viii)</strong> periods of regular and systematic casual employment with an Employer, Statutory Body, Institution or the Australian Red Cross Blood Service (however titled) in Victoria, including prior service as an Other Casual Employee, save that if long service leave was already taken or paid in lieu in respect of any such period, no further benefit to long service leave will arise in respect of that period.</p><p><strong>b.</strong> Periods that do not break Continuous Service, but do not count towards Continuous Service Unless otherwise agreed in writing in advance between the Employer and Employee, the following periods do not break Continuous Service but do not count towards an employee&#39;s Continuous Service for the purpose of calculating the employee&#39;s long service leave entitlement:</p><p><strong>(i)</strong> any authorised period of unpaid leave not referred to in sub-clause 67.5a;</p><p><strong>(ii)</strong> subject to the requirements of the Act, any interruption arising directly or indirectly from an industrial dispute;</p><p><strong>(iii)</strong> any period between the engagement with one Institution, Statutory Body or the Australian Red Cross Blood Service (however titled) and another provided it is less than the allowable period of absence from employment;</p><p><strong>(iv)</strong> the dismissal of an employee if the employee is re-employed by the same Employer within a period not exceeding two months from the date of such dismissal;</p><p><strong>(v)</strong> up to (but not including) the commencement date of this Agreement, any absence on account of injury arising out of or in the course of her/his employment not covered by a period in which an Employee is receiving accident make up pay or other paid leave; and</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(vi)</strong> any absence from work for a period not exceeding twelve months in respect of any pregnancy not covered by 67.5a(i) or 67.5a(vii)</p><p><strong>67.6</strong> Taking of leave</p><p><strong>a.</strong> When leave is to be taken Long service leave will be granted by the Employer within six months from the date of the entitlement arising under clause 67.4asave that:</p><p><strong>(i)</strong> long service leave may be postponed to a mutually agreeable date;</p><p><strong>(ii)</strong> if agreement cannot be reached: <strong>(A)</strong> for a full-time Employee, part-time Employee, or Locum Pharmacist, the date will be determined by FWC: provided that no such determination shall require such leave to commence before the expiry of six months from the date of such determination; and <strong>(B)</strong> for a Regular Casual Employee: (1) the date may be determined by the Employee save that the Employer may refuse the date nominated by an Employee on reasonable business grounds.; or (2) the Employer may direct the Employee to take long service leave at a specified time and for a specified period by giving the Employee at least 12 weeks&#39; written notice. Subject to an order of the Industrial Division of the Magistrates&#39; Court, the Employee must comply with this direction.</p><p><strong>b.</strong> How leave is to be taken Long service leave may be taken in any number of periods of no less than one day as agreed between the Employee and the Employer or as otherwise agreed as part of a transition to retirement.</p><p><strong>c.</strong> Long service leave in advance</p><p><strong>(i)</strong> If an Employee has completed ten years&#39; Continuous Service, an Employer may, by agreement, grant long service leave in advance on a pro rata basis.</p><p><strong>(ii)</strong> Supplementary to subclause 67.6c(i) and subject to subclause 67.6c(iii): <strong>(A)</strong> if a full-time Employee, part-time Employee, or Locum Pharmacist requests to take long service leave under clause 67.4b, the Employer must grant the Employee&#39;s request to take long service leave as soon as practicable unless the Employer has reasonable business grounds for refusing the request; and/or <strong>(B)</strong> for a Regular Casual Employee, an Employer may, by agreement with the Employee, grant long service leave in advance on a pro rata basis at any time.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(iii)</strong> If an Employee takes long service leave in advance and the Employee&#39;s employment ends before the entitlement to the leave would otherwise have accrued: <strong>(A)</strong> the Employer may, from whatever amount is payable to the Employee upon termination, deduct the amount paid to the Employee for the leave in respect of which the Employee was not entitled, if: (1) in the case of a full-time Employee, part-time Employee, or Locum Pharmacist, the termination was for serious and wilful misconduct; or (2) in the case of a Regular Casual Employee, the Employee had accrued less than 7 years&#39; Continuous Service with the Employer as at the termination date; and <strong>(B)</strong> where such a deduction is made, the relevant period of service will not count as a period in respect of which long service leave has already been taken (or paid in lieu) for the purpose of clause 67.5aabove (Periods that count towards Continuous Service).</p><p><strong>d.</strong> Flexible taking of leave An Employee may, subject to approval by the Employer, convert their long service leave entitlement by taking double the period of approved long service leave at half Pay.</p><p><strong>67.7</strong> Payment on termination of employment</p><p><strong>a.</strong> Interpretation For the purposes of this clause 67.7, termination of employment has its ordinary meaning, provided that:</p><p><strong>(i)</strong> it is taken to occur upon conversion from full-time or part-time employment to casual employment; and</p><p><strong>(ii)</strong> it is not taken to occur at the cessation of each shift as a casual Employee.</p><p><strong>b.</strong> Basic entitlement at termination of employment Except where an election is made under clause 67.7cbelow, an Employee is entitled to payment in lieu of untaken long service leave upon termination of employment if, as at the termination date one of the following applies (where multiple options apply to an Employee, the higher benefit will be applied):</p><p><strong>(i)</strong> the Employee has accrued a full long service leave entitlement under clause 67.4aabove, in which case the entitlement shall be calculated at one thirtieth of the period of Continuous Service; or</p><p><strong>(ii)</strong> the Employee has an entitlement to pro rata long service leave under clause 67.4band was not terminated for serious and wilful misconduct, in which case the entitlement shall be calculated at one thirtieth of the period of Continuous Service; or</p><p><strong>(iii)</strong> in the case of a Regular Casual Employee, the Employee has accrued at least 7 years&#39; Continuous Service with the Employer, in</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>which case the entitlement shall be calculated in accordance with the LSL Act.</p><p><strong>c.</strong> Election for payment of entitlement or transfer of entitlement at termination</p><p><strong>(i)</strong> This subclause applies to the following Employees: <strong>(A)</strong> Full-time Employees, part-time Employees and Locum Pharmacists who have an entitlement to be paid pro rata long service leave under clause 67.4b(who therefore have less than fifteen years&#39; accrued Continuous Service with an Employer); and <strong>(B)</strong> Regular Casual Employees who have at least seven years&#39; accrued Continuous Service with an Employer.</p><p><strong>(ii)</strong> An Employee to whom subclause 67.7c(i) applies who intends to be re-employed by another Institution or Statutory Body, may: <strong>(A)</strong> request in writing that payment for accrued long service leave be deferred until after the Employee’s allowable period of absence (as defined above) has expired; and <strong>(B)</strong> where the Employee notifies the initial Employer in writing within the allowable period of absence that the Employee has been employed by such an employer, and the re- employment meets the criteria set out in in subclause 67.7c(iv)below, the initial Employer is no longer required to make payment to the Employee in respect of such service.</p><p><strong>(iii)</strong> Where the notice referred to at 67.7c(ii)(B). is not provided prior to or within the allowable period of absence the Employer will, upon the expiration of the allowable period of absence, make payment in lieu of long service leave as per subclause 67.7b</p><p><strong>(iv)</strong> For the purposes of this subclause, re-employment by another Institution or Statutory Body means employment other than as a Other Casual Employee.</p><p><strong>d.</strong> Payment in lieu of long service leave on the death of an Employee Where an Employee dies while still in the employ of the Employer, payment in lieu of long service leave will be made to the Employee’s personal representative in accordance with clause 67.7babove.</p><p><strong>e.</strong> No entitlement arising for periods of leave already taken For the removal of doubt, where an Employee makes an election under clause 67.7c such that their previous Service is recognised by the new Employer, the Employee’s previous Employer is no longer liable to make any payment in lieu of that employee’s service.</p><p><strong>67.8</strong> Public holidays See also <a href="/eba/ebas/mspp/leave/80-public-holidays.html">clause 80</a>(Public Holidays). Long service leave is inclusive of any public holiday occurring during the period when leave is taken.</p><p><strong>67.9</strong> Transitional Arrangements for Parental Leave taken after 1 November 2018 and before the commencement date of this Agreement Note 1: Unpaid Parental Leave taken prior to 1 November 2018 does not count as Continuous Service unless otherwise agreed, per clause 67.5a(vii)(A).</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>Note 2: Unpaid Parental Leave taken after the commencement date of this Agreement will constitute Continuous Service, per clause 67.5a(vii)(C)(2)).</p><p><strong>a.</strong> As an exception to clause 67.5a, an Employee who took a period of unpaid Parental Leave that included any part of the period between 1 November 2018 and the commencement date of this agreement (inclusive) may make an application to the Employer to have that service recognised for Long Service Leave purposes. The Employer will approve the application and update the Employee&#39;s Long Service Leave record.</p><p><strong>b.</strong> An Employee electing to make an application under 67.9amust make the application to the Employer no later than 6 months of the following (whichever occurs last):</p><p><strong>(i)</strong> the date on which this Agreement commences; or</p><p><strong>(ii)</strong> the date on which the Employee returns to work after the qualifying period of unpaid Parental Leave.</p><p><strong>c.</strong> This clause 67.9 shall also apply to an Employee in respect of a former Employer if the Employee took a qualifying unpaid period of Parental Leave under this clause while employed by that former Employer.</p><p><strong>67.10</strong> Entitlement Save for the matters set out in this part, Other Casual Employees shall be entitled to long service leave with ordinary pay in accordance with the LSL Act.</p><p><strong>67.11</strong> Flexible taking of leave: double leave at half pay</p><p><strong>a.</strong> An employee may request an Employee to take double the period of long service leave at half pay.</p><p><strong>b.</strong> An Employer must grant such a request unless:</p><p><strong>(i)</strong> granting the request would result in an additional cost to the Employer; or</p><p><strong>(ii)</strong> the Employer otherwise has reasonable business grounds for refusing the request.</p><p><strong>c.</strong> Employees should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 67.11a . The Employer will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>d.</strong> The Employer, if requested by the Employee, will provide information as to the amount of tax the Employer intends to deduct where payment of long service leave is sought under this subclause.</p><p><strong>67.12</strong> Payment for period of leave</p><p><strong>a.</strong> Payment will be made in one of the following ways:</p><p><strong>(i)</strong> in full advance when the Employee commences his/her/their leave;</p><p><strong>(ii)</strong> at the same time as payment would have been made if the Employee had remained on duty; in which case payment shall, if the employee in writing so requires, be made by cheque posted to a specified address; or</p><p><strong>(iii)</strong> in any other way agreed between the Employer and the Employee.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>b.</strong> Where an Employee has been paid in advance, and an increase occurs in the ordinary time rate of pay during the period of long service leave taken, the Employee will be entitled to receive payment of the amount of any increase in pay at the completion of such leave.</p><p><strong>67.13</strong> Proof of Sufficient Aggregate Service The onus of proving a sufficient aggregate of service to support a claim for any long service leave entitlement will at all times rest upon the Employee concerned. A Certificate of Service will constitute acceptable proof.</p><p><strong>67.14</strong> Records The Employer will keep a long service leave record for each Employee, containing particulars of service, leave taken and payments made including in relation to prior service with an Institution, Statutory Body or the Australian Red Cross Blood Service (however titled) as provided in 67.2i Where a Transfer of Business occurs, an Employee who worked with the old Employer and who continues in the service of the new Employer will be entitled to count their service with the old Employer as service with the new Employer for the purposes of this clause.</p><p><strong>67.15</strong> Concurrent Service</p><p><strong>a.</strong> Subject to subclause 67.15b, concurrent service with two or more Employers remains separate and distinct.</p><p><strong>b.</strong> If a full-time Employee, part-time Employee, Locum Pharmacist or Regular Casual Employee who was employed with an Employer (the first Employer) becomes employed by another employer (the new Employer) in an equivalent role, but retains concurrent employment with the first Employer as a casual Employee, then the Employee&#39;s service with the first Employer may transfer to the new Employer (despite the Employee remaining employed with the first Employer), if:</p><p><strong>(i)</strong> the Employee does not have an entitlement to take long service leave under clause 67.4a;</p><p><strong>(ii)</strong> the Employee has not already taken or been paid in lieu of long service leave in respect of the relevant period; and</p><p><strong>(iii)</strong> either: <strong>(A)</strong> the Employee notifies the first Employer of the transfer in accordance with sub-clause 67.7c(Election for payment of entitlement or transfer of entitlement at termination); or <strong>(B)</strong> the second Employer otherwise confirms in writing to the first Employer that the period of service has been so recognised (for the removal of doubt, if the second Employer determines to recognise the Employee&#39;s service with the first Employer, it must provide written notification of its determination to the first Employer).</p><p><strong>c.</strong> If a full-time Employee, part-time Employee, Locum Pharmacist or Regular Casual Employee&#39;s long service leave entitlement is transferred in accordance with subclause 67.15b:</p><p><strong>(i)</strong> the first Employer will no longer be liable for the service, and the long service leave liability for the service as a full-time Employee, part- time Employee, Locum Pharmacist or Regular Casual Employee with the first Employer will transfer to the new Employer;</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(ii)</strong> any casual service that occurs with the first Employer after the transfer referred to in (i)above will be considered separate and distinct service on and from the date on which the Employee commenced employment with the new Employer, provided that: <strong>(A)</strong> the qualifying period required to accrue an entitlement to long service leave with the first Employer does not reset (that is, the Employee&#39;s prior service with the first Employer can be counted when calculating any future entitlement to long service leave with the first Employer); <strong>(B)</strong> no benefit to long service leave will arise with the first Employer in respect of the prior period of employment with the first Employer; and <strong>(C)</strong> the Employee&#39;s prior service with the first Employer is disregarded when calculating the Employee&#39;s normal weekly hours with the first Employer (e.g. for the purpose of sections 16 and 17 of the LSL Act).</p><p><strong>(iii)</strong> If the Employee is not entitled to transfer their service from the first Employer to the new Employer, or does not take the steps required in sub-clause 67.7cwithin the allowable period of absence, the first Employer will make payment in lieu of long service leave for the Continuous Service with the first Employer in accordance with clause 67.7b(Basic entitlement at termination of employment). Example 1: A part-time Employee is employed at the same time by Employer 1, and Employer 2. The part-time Employee accrues service towards long service leave at each of Employer 1 and Employer 2. If the Employee had been employed by Employer 1 for 11 years and Employer 2 for 6 years, the Employee can take LSL from Employer 1, but would need to continue working at Employer 2 until sufficient Continuous Service had accrued. If the Employee resigned from both Employer 1 and Employer 2, and went to work for Employer 3, the Employee could:</p><p><strong>(a)</strong> transfer the 6 years&#39; service with Employer 2 to Employer 3; and</p><p><strong>(b)</strong> have the accrued LSL from the 11 years&#39; service with Employer 1 paid out in lieu on termination. Example 2: A Regular Casual Employee has worked for Employer 1 for 6 years. The Employee commences employment with Employer 2 as a full-time Employee. To take up this opportunity, the Employee ceases permanent employment with Employer 1. However, the Employee commences a casual employment relationship with Employer 1 within 12 weeks after resigning from their permanent position with Employer 1. The Employee:</p><p><strong>(a)</strong> could transfer the 6 years&#39; service with Employer 1 to Employer 2, and would be eligible to take LSL with Employer 2 once sufficient Continuous Service had accrued (taking into account the transferred service); and</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(b)</strong> could also take LSL on a pro rata basis with Employer 1 after sufficient Continuous Service had accrued, save that no entitlement would arise in respect of the prior 6 years&#39; service that had been transferred to Employer 2.</p><p><strong>67.16</strong> Savings</p><p><strong>a.</strong> (a) Clauses 67.7c, 67.8, 67.9band 67.15band 67.15cshall not apply to a Regular Casual Employee, unless the Industrial Division of the Magistrates Court provides an opinion that determines generally the rights of applicable Employees under this Agreement under sub-section 23(2) of the LSL Act that the long service leave entitlements provided by this Agreement are more favourable than those provided by the LSL Act.</p><p><strong>b.</strong> (b) The HSU and VHIA must make an application to the Magistrates Court under section 24 of the LSL Act for an opinion referred to in section 67.16a as soon as reasonably practicable after the Agreement has been approved by the Fair Work Commission.</p><p><strong>c.</strong> (c) No Employee shall otherwise suffer any detriment as a result of the operation of this clause to their entitlement to long service leave existing immediately prior to the coming into force of this clause.</p><p>Plain language terms: LSL, long service.</p>',133)])])}const d=t(r,[["render",i]]);export{u as __pageData,d as default};
